import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  beforeEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path by sorting notes in descending order of updatedAt', () => {
    const notes = [
      { id: 1, title: 'Note A', updatedAt: '2023-01-01T10:00:00Z' },
      { id: 2, title: 'Note B', updatedAt: '2023-01-02T12:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-01-01T08:30:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted).toEqual([
      { id: 2, title: 'Note B', updatedAt: '2023-01-02T12:00:00Z' },
      { id: 1, title: 'Note A', updatedAt: '2023-01-01T10:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-01-01T08:30:00Z' },
    ]);
  });

  it('should handle edge case where notes have identical updatedAt values', () => {
    const notes = [
      { id: 1, title: 'Note A', updatedAt: '2023-03-15T09:00:00Z' },
      { id: 2, title: 'Note B', updatedAt: '2023-03-15T09:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-03-14T11:00:00Z' },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    // Identical timestamps should preserve original relative order (stable sort)
    expect(sorted).toEqual([
      { id: 1, title: 'Note A', updatedAt: '2023-03-15T09:00:00Z' },
      { id: 2, title: 'Note B', updatedAt: '2023-03-15T09:00:00Z' },
      { id: 3, title: 'Note C', updatedAt: '2023-03-14T11:00:00Z' },
    ]);
  });

  it('should handle null/empty inputs by returning an empty array', () => {
    expect(sortNotesByUpdatedAt(null as any)).toEqual([]);
    expect(sortNotesByUpdatedAt(undefined as any)).toEqual([]);
    expect(sortNotesByUpdatedAt([])).toEqual([]);
    expect(sortNotesByUpdatedAt('' as any)).toEqual([]);
    expect(sortNotesByUpdatedAt(0 as any)).toEqual([]);
  });
});

